  ('3385d4a5-b4c2-5331-a7a9-53a03f3f4869', '3e86c71d-dde1-5553-ac14-ee6addfea988', '14a89caf-39e6-5111-a996-4832e2aab736', 'Ask a few simple questions&nbsp;to each person&nbsp;about what their skills are, then&nbsp;allocate&nbsp;tasks based on their strengths.​', 1, 59, 'Finished Abnormally'),
  ('3385d4a5-b4c2-5331-a7a9-53a03f3f4869', '3e86c71d-dde1-5553-ac14-ee6addfea988', '8e8da4f5-dcf2-5c19-af58-fd994509b25e', '''You’re&nbsp;not messing up.&nbsp;We can’t do this without you. If we&nbsp;practice a bit more,I’m sure you’ll&nbsp;feel more confident.’​', 1, 92, 'Finished Abnormally'),
